@startuml
!theme base

package "php" as php {
  package "SPL" as spl {
    interface "ArrayAccess" as ArrayAccess {
      offsetExists(offset)
      offsetGet(offset)
      offsetSet(offset, value)
      offsetUnset(offset)
    }
    interface "Countable" as Countable {
      count()
    }
    interface "Iterator" as Iterator {
      current()
      next()
      key()
      valid()
      rewind()
    }
    class "SplFixedArray" as SplFixedArray {
    }
  }
}

package "Digitick" as digitick {
  package "Foundation" as foundation {
    package "Collection" as collection {
      interface "InterfaceCollection" as InterfaceCollection {
        addAll(InterfaceCollection elementCollection)
        clear()
        contains(element)
        containsAll(InterfaceCollection elementCollection)
        isEmpty()
        removeAll(InterfaceCollection elementCollection)
        size()
        toArray()
      }
      interface "InterfaceSet" as InterfaceSet {
        add(element)
        get(element)
        remove(element)
      }
      interface "InterfaceList" as InterfaceList {
        add(offset, element)
        remove(offset)
        get(offset)
        set(offset, element)
        indexOf(element)
        subList(fromIndex, toIndex)
      }
      trait "TraitCollection" as TraitCollection {
        indexOf(element, collectionObject)
        contains(element, collectionObject)
      }
      abstract class "AbstractScalarSet" as AbstractScalarSet {
        DEFAULT_SIZE
        nextAvailableOffset
        storageArray
        increaseSize(quantity=1)
        decreaseSize(quantity=1)
        shift(fromOffset)
        removeOffset(offset)
      }
      abstract class "AbstractObjectSet" as AbstractObjectSet {
        storageArray
        nextAvailableOffset
        set(element, data)
      }
      abstract class "TraitTypedCollection" as TraitTypedCollection {
        CLASSORTYPENAME
        checkelementType(element)
      }
      abstract class "AbstractList" as AbstractList {
      }
      abstract class "AbstractTypedScalarSet" as AbstractTypedScalarSet {
      }
      abstract class "AbstractTypedObjectSet" as AbstractTypedObjectSet {
      }
      abstract class "AbstractTypedList" as AbstractTypedList {
      }
      class "BaseObjectSet" as BaseObjectSet {
      }
      class "BaseScalarSet" as BaseScalarSet {
      }
      class "IntScalarSet" as IntScalarSet {
      }
      class "StringScalarSet" as StringScalarSet {
      }
      class "BaseList" as BaseList {
      }
      class "IntList" as IntList {
      }
      class "StringList" as StringList {
      }
    }
  }
}

InterfaceCollection <|-- InterfaceSet
InterfaceCollection <|-- InterfaceList
InterfaceSet <|-- AbstractObjectSet
InterfaceSet <|-- AbstractScalarSet
InterfaceList <|-- AbstractList
AbstractObjectSet <|-- BaseObjectSet
AbstractObjectSet <|-- AbstractTypedObjectSet
AbstractScalarSet <|-- BaseScalarSet
AbstractScalarSet <|-- IntScalarSet
AbstractScalarSet <|-- StringScalarSet
AbstractScalarSet <|-- AbstractTypedScalarSet
AbstractList <|-- BaseList
AbstractList <|-- AbstractTypedList
AbstractTypedList <|-- IntList
AbstractTypedList <|-- StringList
TraitCollection <|-- AbstractObjectSet
TraitCollection <|-- AbstractScalarSet
TraitTypedCollection <|-- AbstractTypedObjectSet
TraitTypedCollection <|-- AbstractTypedList

InterfaceCollection ..> ArrayAccess
InterfaceCollection ..> Countable
InterfaceCollection ..> Iterator
InterfaceCollection ..> SplFixedArray

@enduml
